commands.examples:
SELECT name, salary,
  salary - (SELECT AVG(salary) FROM employees) AS diff_from_avg
FROM employees;

-- User yang punya order
SELECT * FROM users u WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id
);

-- User tanpa order (anti-join)
SELECT * FROM users u WHERE NOT EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id
);

-- Gaji lebih dari rata-rata di departemen manapun
SELECT * FROM employees WHERE salary > ANY (
  SELECT AVG(salary) FROM employees GROUP BY dept_id
);

-- Gaji lebih dari semua rata-rata departemen
SELECT * FROM employees WHERE salary > ALL (
  SELECT AVG(salary) FROM employees GROUP BY dept_id
);

-- Employee dengan gaji di atas rata-rata departemennya
SELECT * FROM employees e
WHERE salary > (
  SELECT AVG(salary) FROM employees WHERE dept_id = e.dept_id
);
